router.get('/', (req, res) => {
  const comments = commentsService.getAllComments(req.projectId, req.taskId);
  res.json({ comments });
});

module.exports = router;

const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

const createComment = (projectId, taskId, comment) => {
  const project = projectsService.getProject(projectId);
  if (!project) {
    return null;
  }

  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }

  const newComment = { ...comment, id: generateId() };
  if (!task.comments) {
    task.comments = [];
  }
  task.comments.push(newComment);
  projectsService.updateProject(project);

  return newComment;
};

const getAllComments = (projectId, taskId) => {
  const project = projectsService.getProject(projectId);
  if (!project) {
    return [];
  }

  const task = project.tasks.find(t => t.id === taskId);
  if (!task || !task.comments) {
    return [];
  }

  return task.comments;
};

module.exports = { createComment, getAllComments };

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.status(200).json({ status: 'OK' });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
}, membersRoutes);
app.use('/projects/:projectId/tasks', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
}, tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', (req, res, next) => {
  req.taskId = req.params.taskId;
  next();
}, commentsRoutes);

module.exports = app;
